import {
  Hammer,
  Flame,
  Paintbrush,
  ScanLine,
  PackageCheck,
  type LucideIcon,
} from "lucide-react";

export interface Station {
  id: string;
  name: string;
  tagline: string;
  description: string;
  Icon: LucideIcon;
  accent: string;
  transform: string;
}

export const STATIONS: Station[] = [
  {
    id: "stamp",
    name: "Stamp",
    tagline: "Press line",
    description:
      "An 800-ton hydraulic press cuts flat sheet stock into panel blanks, dropping one every 4.2 seconds.",
    Icon: Hammer,
    accent: "#f59e0b",
    transform: "Cut to shape",
  },
  {
    id: "weld",
    name: "Weld",
    tagline: "Joining cell",
    description:
      "Six-axis arms fuse the stamped panels into a rigid chassis frame along the primary seam.",
    Icon: Flame,
    accent: "#ef4444",
    transform: "Frame joined",
  },
  {
    id: "paint",
    name: "Paint",
    tagline: "Finish booth",
    description:
      "Electrostatic bells apply primer, color coat, and clear topcoat in a single pass.",
    Icon: Paintbrush,
    accent: "#3b82f6",
    transform: "Color applied",
  },
  {
    id: "inspect",
    name: "Inspect",
    tagline: "QC scanner",
    description:
      "A laser raster verifies dimensional tolerances and surface finish to \u00b120 \u00b5m.",
    Icon: ScanLine,
    accent: "#22c55e",
    transform: "Verified",
  },
  {
    id: "pack",
    name: "Pack",
    tagline: "Outbound",
    description:
      "The finished unit is crated, labeled, and routed to the loading dock for shipment.",
    Icon: PackageCheck,
    accent: "#a855f7",
    transform: "Ready to ship",
  },
];

export interface Caption {
  tag: string;
  name: string;
  desc: string;
}

export const INTRO_CAPTION: Caption = {
  tag: "RAW STOCK",
  name: "Awaiting line",
  desc: "Scroll to drive the workpiece through five assembly stations.",
};

export const DONE_CAPTION: Caption = {
  tag: "COMPLETE",
  name: "Outbound",
  desc: "The unit has cleared every station and is heading to the loading dock.",
};

export function stationCaption(i: number): Caption {
  const s = STATIONS[i];
  return {
    tag: `STATION 0${i + 1} \u00b7 ${s.tagline.toUpperCase()}`,
    name: s.name,
    desc: s.description,
  };
}

import { useEffect, useRef } from "react";
import {
  STATIONS,
  INTRO_CAPTION,
  DONE_CAPTION,
  stationCaption,
} from "./stations";

const STATION_X = (i: number) => 10 + i * 20; // 10,30,50,70,90 (%)
const PART_X_MIN = 5;
const PART_X_MAX = 95;
const STATION_HALF_WIDTH = 7; // % around station center where the tool is "over" it

export function AssemblyScroll({ reduced, onToggle }: { reduced: boolean; onToggle: () => void }) {
  const trackRef = useRef<HTMLDivElement>(null);
  const partRef = useRef<HTMLDivElement>(null);
  const fillRef = useRef<HTMLDivElement>(null);
  const readoutRef = useRef<HTMLSpanElement>(null);
  const captionTagRef = useRef<HTMLSpanElement>(null);
  const captionNameRef = useRef<HTMLHeadingElement>(null);
  const captionDescRef = useRef<HTMLParagraphElement>(null);
  const toolRefs = useRef<Array<HTMLDivElement | null>>([]);
  const glowRefs = useRef<Array<HTMLDivElement | null>>([]);
  const sparkRefs = useRef<Array<HTMLDivElement | null>>([]);
  const checkRefs = useRef<Array<HTMLSpanElement | null>>([]);
  const lastCapRef = useRef<number>(-99);

  useEffect(() => {
    let raf = 0;
    const track = trackRef.current;
    const part = partRef.current;
    if (!track || !part) return;

    const compute = () => {
      raf = 0;
      const rect = track.getBoundingClientRect();
      const trackable = track.offsetHeight - window.innerHeight;
      const scrolled = -rect.top;
      const p = trackable > 0 ? Math.min(1, Math.max(0, scrolled / trackable)) : 0;

      const partX = PART_X_MIN + p * (PART_X_MAX - PART_X_MIN);
      part.style.left = partX + "%";

      if (fillRef.current) fillRef.current.style.width = p * 100 + "%";
      if (readoutRef.current) readoutRef.current.textContent = Math.round(p * 100) + "%";

      let activeIdx = -1;
      for (let i = 0; i < STATIONS.length; i++) {
        const sx = STATION_X(i);
        const dist = Math.abs(partX - sx);
        const ext = Math.max(0, 1 - dist / STATION_HALF_WIDTH); // 0..1 tool extension
        const tool = toolRefs.current[i];
        if (tool) {
          tool.style.transform = `translateY(${-30 + ext * 36}px)`;
          tool.style.opacity = String(0.45 + ext * 0.55);
        }
        const glow = glowRefs.current[i];
        if (glow) glow.style.opacity = String(ext);
        const spark = sparkRefs.current[i];
        if (spark) spark.style.opacity = String(ext);
        const completed = partX > sx + 3.5;
        const check = checkRefs.current[i];
        if (check) check.style.opacity = completed ? "1" : "0";
        if (ext > 0.55) activeIdx = i;
      }

      // cumulative stage: how many stations fully passed
      let stage = 0;
      for (let i = 0; i < STATIONS.length; i++) {
        if (partX > STATION_X(i) + 3.5) stage = i + 1;
      }
      part.dataset.stage = String(stage);

      // caption index: -1 intro, 0..4 station, 5 complete
      let capIdx: number;
      if (partX > 93) capIdx = 5;
      else if (activeIdx >= 0) capIdx = activeIdx;
      else if (stage === 0) capIdx = -1;
      else capIdx = Math.min(STATIONS.length - 1, stage - 1);

      if (capIdx !== lastCapRef.current) {
        lastCapRef.current = capIdx;
        const cap = capIdx === -1 ? INTRO_CAPTION : capIdx === 5 ? DONE_CAPTION : stationCaption(capIdx);
        if (captionTagRef.current) captionTagRef.current.textContent = cap.tag;
        if (captionNameRef.current) captionNameRef.current.textContent = cap.name;
        if (captionDescRef.current) captionDescRef.current.textContent = cap.desc;
      }
    };

    const schedule = () => {
      if (!raf) raf = requestAnimationFrame(compute);
    };

    window.addEventListener("scroll", schedule, { passive: true });
    window.addEventListener("resize", schedule, { passive: true });
    compute();
    return () => {
      window.removeEventListener("scroll", schedule);
      window.removeEventListener("resize", schedule);
      if (raf) cancelAnimationFrame(raf);
    };
  }, []);

  return (
    <section className="experience" aria-label="Assembly line scroll experience">
      <div ref={trackRef} className="scroll-track">
        <div className="sticky-stage">
          <div className="stage-frame">
            <div className="status-bar">
              <span className="status-dot" aria-hidden="true" />
              <span className="status-label">LINE&nbsp;07&nbsp;\u2014&nbsp;ASSEMBLY</span>
              <span className="status-spacer" />
              <span className="status-readout">
                <span ref={readoutRef}>0%</span>
              </span>
            </div>
            <div className="progress-bar" aria-hidden="true">
              <div ref={fillRef} className="progress-fill" />
            </div>
          </div>

          <div className="machine">
            <div className="stations-row">
              {STATIONS.map((s, i) => (
                <div
                  className="station"
                  key={s.id}
                  style={{ left: `${STATION_X(i)}%`, ["--accent" as string]: s.accent }}
                >
                  <div className="station-glow" ref={(el) => { glowRefs.current[i] = el; }} aria-hidden="true" />
                  <div className="tool-arm" ref={(el) => { toolRefs.current[i] = el; }} aria-hidden="true">
                    <s.Icon size={20} strokeWidth={2.2} />
                  </div>
                  <div className="station-spark" ref={(el) => { sparkRefs.current[i] = el; }} aria-hidden="true">
                    <span /><span /><span />
                  </div>
                  <div className="station-label">
                    <span className="station-num">0{i + 1}</span>
                    <span className="station-name">{s.name}</span>
                  </div>
                  <span className="station-check" ref={(el) => { checkRefs.current[i] = el; }} aria-hidden="true">
                    \u2713
                  </span>
                </div>
              ))}
            </div>

            <div className="conveyor" aria-hidden="true">
              <div className="belt" />
              <div className="belt-edge belt-edge-top" />
              <div className="belt-edge belt-edge-bottom" />
              <div className="part" ref={partRef} data-stage="0">
                <div className="part-body" />
                <div className="part-rivets" />
                <div className="part-coat" />
                <div className="part-shine" />
                <div className="part-check">\u2713</div>
                <div className="part-crate">
                  <span className="crate-tape" />
                </div>
              </div>
            </div>

            <div className="caption">
              <span ref={captionTagRef} className="caption-tag">{INTRO_CAPTION.tag}</span>
              <h2 ref={captionNameRef} className="caption-name">{INTRO_CAPTION.name}</h2>
              <p ref={captionDescRef} className="caption-desc">{INTRO_CAPTION.desc}</p>
            </div>
          </div>

          <div className="stage-hint" aria-hidden="true">
            <span className="hint-text">Scroll drives the line</span>
            <span className="hint-arrow" />
          </div>
        </div>
      </div>

      <ModeToggle reduced={reduced} onToggle={onToggle} />
    </section>
  );
}

export function ModeToggle({ reduced, onToggle }: { reduced: boolean; onToggle: () => void }) {
  return (
    <button
      type="button"
      className="mode-toggle"
      onClick={onToggle}
      aria-pressed={reduced}
      title="Switch between scroll-driven and reduced-motion views"
    >
      <span className="mode-toggle-dot" data-active={!reduced} />
      {reduced ? "Reduced motion" : "Scroll-driven"}
      <span className="mode-toggle-sub">\u00b7 tap to switch</span>
    </button>
  );
}

import { useEffect, useRef, useState } from "react";
import { STATIONS } from "./stations";
import { ModeToggle } from "./AssemblyScroll";

export function AssemblyStatic({ reduced, onToggle }: { reduced: boolean; onToggle: () => void }) {
  const [step, setStep] = useState<number>(0); // 0 = raw, 1..5 = after station i, 6 = shipped
  const liveRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    liveRef.current?.setAttribute("data-stage", String(step));
  }, [step]);

  const total = STATIONS.length + 1; // 0..5

  const go = (delta: number) => {
    setStep((s) => Math.max(0, Math.min(total, s + delta)));
  };

  return (
    <section className="static-exp" aria-label="Assembly line, reduced motion">
      <div className="static-head">
        <div>
          <span className="kicker">REDUCED MOTION</span>
          <h2>Step through the line</h2>
          <p>
            No scroll-linked motion. Use the controls (or arrow keys) to advance the
            workpiece one station at a time. Every station is also described below.
          </p>
        </div>
        <ModeToggle reduced={reduced} onToggle={onToggle} />
      </div>

      <div className="static-stage">
        <div className="static-roadmap">
          {STATIONS.map((s, i) => {
            const reached = step > i;
            const active = step === i + 1 || (i === 0 && step === 0);
            return (
              <button
                type="button"
                key={s.id}
                className={"roadmap-pill" + (reached ? " is-reached" : "") + (active ? " is-active" : "")}
                style={{ ["--accent" as string]: s.accent }}
                onClick={() => setStep(i + 1)}
                aria-label={`Jump to ${s.name}`}
              >
                <s.Icon size={16} strokeWidth={2.4} />
                <span>{s.name}</span>
                <span className="roadmap-num">0{i + 1}</span>
              </button>
            );
          })}
        </div>

        <div className="static-display">
          <div className="display-rail" aria-hidden="true">
            <span className="display-rail-track" />
          </div>
          <div className="part part-lg" ref={liveRef} data-stage={step} aria-label={`Workpiece at stage ${step} of ${total}`}>
            <div className="part-body" />
            <div className="part-rivets" />
            <div className="part-coat" />
            <div className="part-shine" />
            <div className="part-check">{"\u2713"}</div>
            <div className="part-crate">
              <span className="crate-tape" />
            </div>
          </div>
          <div className="display-caption">
            <StaticCaption step={step} />
          </div>
        </div>

        <div className="static-controls">
          <button type="button" onClick={() => go(-1)} disabled={step <= 0} aria-label="Previous step">
            {"\u2190 Prev"}
          </button>
          <span className="step-readout">{step} / {total}</span>
          <button type="button" onClick={() => go(1)} disabled={step >= total} aria-label="Next step">
            {"Next \u2192"}
          </button>
        </div>
      </div>

      <div className="static-cards">
        {STATIONS.map((s, i) => (
          <article className="station-card" key={s.id} style={{ ["--accent" as string]: s.accent }}>
            <header>
              <span className="card-icon"><s.Icon size={18} strokeWidth={2.2} /></span>
              <span className="card-num">STATION 0{i + 1}</span>
            </header>
            <h3>{s.name}<span className="card-tag">{s.tagline}</span></h3>
            <p>{s.description}</p>
            <footer className="card-foot">
              <span className="card-xform">{s.transform}</span>
            </footer>
          </article>
        ))}
      </div>
    </section>
  );
}

function StaticCaption({ step }: { step: number }) {
  if (step === 0) {
    return (
      <>
        <span className="caption-tag">RAW STOCK</span>
        <strong>Awaiting line</strong>
        <em>Flat sheet stock, not yet processed.</em>
      </>
    );
  }
  if (step > STATIONS.length) {
    return (
      <>
        <span className="caption-tag">COMPLETE</span>
        <strong>Outbound</strong>
        <em>Finished unit, routed to the loading dock.</em>
      </>
    );
  }
  const s = STATIONS[step - 1];
  return (
    <>
      <span className="caption-tag" style={{ color: s.accent }}>{`STATION 0${step} \u00b7 ${s.tagline.toUpperCase()}`}</span>
      <strong>{s.name}</strong>
      <em>{s.description}</em>
    </>
  );
}

import { useEffect, useState } from "react";
import { Factory, Github, MousePointerClick } from "lucide-react";
import { STATIONS } from "./stations";
import { AssemblyScroll } from "./AssemblyScroll";
import { AssemblyStatic } from "./AssemblyStatic";

const STORAGE_KEY = "furmark-assembly-reduced";

function prefersReduced(): boolean {
  if (typeof window === "undefined" || !window.matchMedia) return false;
  return window.matchMedia("(prefers-reduced-motion: reduce)").matches;
}

export default function App() {
  const [reduced, setReduced] = useState<boolean>(false);
  const [ready, setReady] = useState<boolean>(false);

  useEffect(() => {
    let initial = prefersReduced();
    try {
      const saved = window.localStorage.getItem(STORAGE_KEY);
      if (saved === "1") initial = true;
      else if (saved === "0") initial = false;
    } catch {
      /* ignore */
    }
    setReduced(initial);
    setReady(true);
  }, []);

  const toggle = () => {
    setReduced((prev) => {
      const next = !prev;
      try {
        window.localStorage.setItem(STORAGE_KEY, next ? "1" : "0");
      } catch {
        /* ignore */
      }
      return next;
    });
  };

  return (
    <div className={"app" + (reduced ? " is-reduced" : "")}>
      <header className="site-head">
        <div className="brand">
          <span className="brand-mark"><Factory size={20} strokeWidth={2.2} /></span>
          <div>
            <span className="brand-name">MERIDIAN WORKS</span>
            <span className="brand-sub">Line 07 \u00b7 Live floor monitor</span>
          </div>
        </div>
        <a className="head-meta" href="#details">
          <MousePointerClick size={14} /> How it works
        </a>
      </header>

      <section className="hero">
        <span className="kicker">SCROLL-DRIVEN MACHINE</span>
        <h1>An assembly line,<br />powered by your scroll.</h1>
        <p>
          A single workpiece travels through {STATIONS.length} stations. Each pixel you scroll
          advances the line a little further \u2014 tools descend, sparks fly, the part is
          transformed. Prefer no motion? Switch to the step-through view any time.
        </p>
        <ul className="hero-stats">
          <li><b>{STATIONS.length}</b><span>stations</span></li>
          <li><b>~4</b><span>screens of scroll</span></li>
          <li><b>0</b><span>state-driven re-renders</span></li>
        </ul>
      </section>

      {ready && (reduced ? (
        <AssemblyStatic reduced={reduced} onToggle={toggle} />
      ) : (
        <AssemblyScroll reduced={reduced} onToggle={toggle} />
      ))}

      <section id="details" className="details">
        <h2>Under the hood</h2>
        <div className="detail-grid">
          <div>
            <h3>Scroll as the driveshaft</h3>
            <p>
              A tall track gives the page real scroll depth. A single passive
              <code> scroll</code> listener schedules one <code>requestAnimationFrame</code> per
              frame; that callback reads the track's bounding box and writes transforms directly
              to DOM nodes. No component state is touched on scroll, so there are no React
              re-render loops and the timeline stays smooth on a 60&nbsp;Hz screen.
            </p>
          </div>
          <div>
            <h3>Reduced motion, same data</h3>
            <p>
              Tapping the mode control (or setting "reduce motion" in your OS) swaps in a static,
              fully readable view: a step-through workpiece plus a card for every station. Nothing
              hijacks the scroll position and nothing animates on its own.
            </p>
          </div>
          <div>
            <h3>Mobile-first layout</h3>
            <p>
              Stations use percentage positions so the belt scales from a 320&nbsp;px phone up to a
              wide desktop. The stage locks to <code>100dvh</code>, the part uses <code>clamp()</code>
              sizing, and every interactive control has a readable tap target.
            </p>
          </div>
        </div>
      </section>

      <footer className="site-foot">
        <span><Github size={14} /> Meridian Works \u00b7 Furmark build</span>
        <span>Line 07 \u00b7 {STATIONS.length} stations \u00b7 build OK</span>
      </footer>
    </div>
  );
}

