:root {
  --bg: #0b0f17;
  --bg-2: #0f1421;
  --panel: #131a2b;
  --panel-2: #1a2236;
  --line: #283149;
  --line-2: #364159;
  --text: #e8ecf5;
  --muted: #93a0b8;
  --muted-2: #6b7689;
  --amber: #f59e0b;
  --green: #22c55e;
  --red: #ef4444;
  --blue: #3b82f6;
  --purple: #a855f7;
  --radius: 14px;
  --radius-sm: 8px;
  --font: "Inter", system-ui, -apple-system, "Segoe UI", Roboto, sans-serif;
  --mono: "JetBrains Mono", ui-monospace, "SF Mono", Menlo, monospace;
}

* { box-sizing: border-box; }

html, body { margin: 0; padding: 0; }

body {
  background:
    radial-gradient(1200px 600px at 80% -10%, rgba(245, 158, 11, 0.08), transparent 60%),
    radial-gradient(900px 500px at -10% 30%, rgba(59, 130, 246, 0.08), transparent 60%),
    var(--bg);
  color: var(--text);
  font-family: var(--font);
  font-size: 16px;
  line-height: 1.5;
  -webkit-font-smoothing: antialiased;
  text-rendering: optimizeLegibility;
}

.app { overflow-x: hidden; }

a { color: inherit; text-decoration: none; }
code {
  font-family: var(--mono);
  font-size: 0.85em;
  background: rgba(255, 255, 255, 0.06);
  padding: 1px 6px;
  border-radius: 4px;
  color: #ffd9a0;
}

/* ---------- HEADER ---------- */
.site-head {
  position: sticky;
  top: 0;
  z-index: 30;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
  padding: 14px clamp(16px, 4vw, 40px);
  background: rgba(11, 15, 23, 0.78);
  backdrop-filter: blur(14px);
  -webkit-backdrop-filter: blur(14px);
  border-bottom: 1px solid var(--line);
}
.brand { display: flex; align-items: center; gap: 12px; }
.brand-mark {
  display: grid; place-items: center;
  width: 36px; height: 36px;
  border-radius: 10px;
  background: linear-gradient(140deg, var(--amber), #b45309);
  color: #1a1206;
  box-shadow: 0 6px 18px rgba(245, 158, 11, 0.35);
}
.brand-name { display: block; font-weight: 700; letter-spacing: 0.12em; font-size: 13px; }
.brand-sub { display: block; font-size: 11px; color: var(--muted-2); letter-spacing: 0.04em; }
.head-meta {
  display: inline-flex; align-items: center; gap: 6px;
  font-size: 13px; color: var(--muted);
  padding: 8px 12px; border: 1px solid var(--line); border-radius: 999px;
  transition: color .2s, border-color .2s, background .2s;
}
.head-meta:hover { color: var(--text); border-color: var(--line-2); background: rgba(255,255,255,0.03); }

/* ---------- HERO ---------- */
.hero {
  max-width: 980px;
  margin: 0 auto;
  padding: clamp(48px, 9vh, 96px) clamp(20px, 5vw, 40px) clamp(40px, 7vh, 72px);
}
.kicker {
  display: inline-block;
  font-size: 11px; letter-spacing: 0.22em; font-weight: 700;
  color: var(--amber);
  padding: 5px 10px;
  border: 1px solid rgba(245, 158, 11, 0.35);
  border-radius: 999px;
  background: rgba(245, 158, 11, 0.07);
}
.hero h1 {
  font-size: clamp(34px, 6.4vw, 68px);
  line-height: 1.02;
  letter-spacing: -0.02em;
  margin: 22px 0 18px;
  font-weight: 800;
}
.hero p {
  max-width: 640px;
  color: var(--muted);
  font-size: clamp(15px, 1.4vw, 18px);
  margin: 0;
}
.hero-stats {
  list-style: none; padding: 0; margin: 32px 0 0;
  display: flex; flex-wrap: wrap; gap: 28px;
}
.hero-stats li { display: flex; flex-direction: column; }
.hero-stats b { font-size: 26px; font-weight: 800; }
.hero-stats span { font-size: 12px; color: var(--muted-2); letter-spacing: 0.04em; }

/* ---------- EXPERIENCE WRAPPER ---------- */
.experience { position: relative; }

.scroll-track {
  position: relative;
  height: 520vh;
}
.sticky-stage {
  position: sticky;
  top: 0;
  height: 100dvh;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  background:
    linear-gradient(180deg, rgba(255,255,255,0.02), transparent 30%),
    radial-gradient(80% 60% at 50% 110%, rgba(245,158,11,0.06), transparent 70%);
}

/* faux floor grid */
.sticky-stage::before {
  content: "";
  position: absolute;
  inset: 0;
  background-image:
    linear-gradient(rgba(255,255,255,0.035) 1px, transparent 1px),
    linear-gradient(90deg, rgba(255,255,255,0.035) 1px, transparent 1px);
  background-size: 48px 48px;
  mask-image: radial-gradient(120% 80% at 50% 40%, #000 30%, transparent 80%);
  -webkit-mask-image: radial-gradient(120% 80% at 50% 40%, #000 30%, transparent 80%);
  pointer-events: none;
}

/* ---------- STAGE FRAME (status + progress) ---------- */
.stage-frame {
  position: relative;
  z-index: 4;
  padding: 18px clamp(20px, 4vw, 40px) 0;
}
.status-bar {
  display: flex; align-items: center; gap: 10px;
  font-family: var(--mono);
  font-size: 12px;
  color: var(--muted);
  letter-spacing: 0.08em;
}
.status-dot {
  width: 8px; height: 8px; border-radius: 50%;
  background: var(--green);
  box-shadow: 0 0 0 0 rgba(34,197,94,0.5);
  animation: pulse 2.4s ease-out infinite;
}
@keyframes pulse {
  0% { box-shadow: 0 0 0 0 rgba(34,197,94,0.55); }
  70% { box-shadow: 0 0 0 10px rgba(34,197,94,0); }
  100% { box-shadow: 0 0 0 0 rgba(34,197,94,0); }
}
.status-label { color: var(--text); }
.status-spacer { flex: 1; }
.status-readout {
  color: var(--amber);
  font-weight: 700;
}
.progress-bar {
  margin-top: 10px;
  height: 4px;
  border-radius: 999px;
  background: rgba(255,255,255,0.06);
  overflow: hidden;
}
.progress-fill {
  height: 100%;
  width: 0%;
  background: linear-gradient(90deg, var(--amber), #fbbf24);
  box-shadow: 0 0 12px rgba(245,158,11,0.6);
  border-radius: inherit;
}

/* ---------- MACHINE ---------- */
.machine {
  position: relative;
  z-index: 3;
  flex: 1;
  display: flex;
  flex-direction: column;
  justify-content: center;
  gap: clamp(8px, 2vh, 24px);
  padding: clamp(16px, 3vh, 40px) clamp(16px, 4vw, 48px);
  max-width: 1280px;
  width: 100%;
  margin: 0 auto;
}

.stations-row {
  position: relative;
  height: clamp(140px, 22vh, 220px);
}

.station {
  position: absolute;
  top: 0;
  transform: translateX(-50%);
  width: clamp(72px, 12vw, 110px);
  display: flex;
  flex-direction: column;
  align-items: center;
}
.station-label {
  margin-top: 8px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 2px;
}
.station-num {
  font-family: var(--mono);
  font-size: 10px;
  color: var(--muted-2);
  letter-spacing: 0.1em;
}
.station-name {
  font-size: 13px;
  font-weight: 700;
  letter-spacing: 0.04em;
  color: var(--text);
}

/* tool arm hangs above the belt; translateY driven by JS */
.tool-arm {
  position: relative;
  width: 46px; height: 46px;
  display: grid; place-items: center;
  border-radius: 12px;
  background: linear-gradient(160deg, var(--panel-2), var(--panel));
  border: 1px solid var(--line-2);
  color: var(--accent, var(--amber));
  box-shadow: 0 8px 20px rgba(0,0,0,0.45), inset 0 1px 0 rgba(255,255,255,0.05);
  transform: translateY(-30px);
  opacity: 0.45;
  will-change: transform, opacity;
}
.tool-arm::after {
  /* shaft connecting tool to ceiling */
  content: "";
  position: absolute;
  left: 50%;
  bottom: 100%;
  width: 2px;
  height: 60px;
  transform: translateX(-50%);
  background: linear-gradient(180deg, transparent, var(--line-2));
}

/* glow under active tool */
.station-glow {
  position: absolute;
  left: 50%;
  top: 52px;
  width: 90px; height: 60px;
  transform: translateX(-50%);
  background: radial-gradient(ellipse at center, var(--accent, var(--amber)) 0%, transparent 65%);
  filter: blur(6px);
  opacity: 0;
  pointer-events: none;
  transition: opacity .12s linear;
}

/* sparks */
.station-spark {
  position: absolute;
  left: 50%;
  top: 46px;
  width: 50px; height: 50px;
  transform: translateX(-50%);
  opacity: 0;
  pointer-events: none;
}
.station-spark span {
  position: absolute;
  left: 50%; top: 50%;
  width: 4px; height: 4px;
  border-radius: 50%;
  background: var(--accent, var(--amber));
  box-shadow: 0 0 6px var(--accent, var(--amber));
}
.station-spark span:nth-child(1) { animation: spark1 0.9s linear infinite; }
.station-spark span:nth-child(2) { animation: spark2 0.9s linear infinite 0.3s; }
.station-spark span:nth-child(3) { animation: spark3 0.9s linear infinite 0.6s; }
@keyframes spark1 {
  0% { transform: translate(-50%,-50%) scale(0.4); opacity: 0; }
  30% { opacity: 1; }
  100% { transform: translate(-260%, -260%) scale(0.2); opacity: 0; }
}
@keyframes spark2 {
  0% { transform: translate(-50%,-50%) scale(0.4); opacity: 0; }
  30% { opacity: 1; }
  100% { transform: translate(220%, -250%) scale(0.2); opacity: 0; }
}
@keyframes spark3 {
  0% { transform: translate(-50%,-50%) scale(0.4); opacity: 0; }
  30% { opacity: 1; }
  100% { transform: translate(-50%, 280%) scale(0.2); opacity: 0; }
}

.station-check {
  position: absolute;
  top: 30px;
  right: -4px;
  width: 20px; height: 20px;
  display: grid; place-items: center;
  font-size: 12px; font-weight: 800;
  color: #04210f;
  background: var(--green);
  border-radius: 50%;
  opacity: 0;
  transform: scale(0.6);
  transition: opacity .25s ease, transform .25s cubic-bezier(.2,1.4,.4,1);
  box-shadow: 0 0 0 3px rgba(34,197,94,0.18);
}
.station .station-check { /* re-apply transform when shown */ }
.station-check:not([style*="opacity: 0"]) { /* not reliable; using opacity only */ }
/* ensure scale when visible: we set opacity via JS; bump scale via attribute-style fallback */

/* ---------- CONVEYOR ---------- */
.conveyor {
  position: relative;
  height: clamp(90px, 14vh, 120px);
  margin-top: auto;
}
.belt {
  position: absolute;
  left: 0; right: 0;
  top: 50%;
  height: 16px;
  transform: translateY(-50%);
  background:
    repeating-linear-gradient(90deg, #2a3346 0 14px, #1c2436 14px 28px);
  background-size: 28px 16px;
  border-top: 1px solid #3a4660;
  border-bottom: 1px solid #11151f;
  animation: beltMove 0.7s linear infinite;
  box-shadow: inset 0 1px 0 rgba(255,255,255,0.04);
}
@keyframes beltMove {
  to { background-position: -28px 0; }
}
.belt-edge {
  position: absolute; left: 0; right: 0; height: 3px;
  background: linear-gradient(90deg, transparent, rgba(245,158,11,0.5), transparent);
}
.belt-edge-top { top: calc(50% - 10px); }
.belt-edge-bottom { bottom: calc(50% - 10px); opacity: 0.5; }

/* ---------- PART (the workpiece) ---------- */
.part {
  position: absolute;
  bottom: calc(50% - 6px);
  left: 5%;
  width: clamp(52px, 7vw, 70px);
  height: clamp(36px, 4.6vw, 48px);
  transform: translate(-50%, 50%);
  transition: background-color .25s ease, border-radius .25s ease, box-shadow .25s ease;
  will-change: left;
}
.part-body {
  position: absolute; inset: 0;
  background: #3a4253;
  border-radius: 3px;
  border: 1px solid #232a3b;
  box-shadow: inset 0 -3px 0 rgba(0,0,0,0.35), inset 0 1px 0 rgba(255,255,255,0.06);
  transition: border-radius .3s ease, background-color .3s ease, box-shadow .3s ease;
}
.part-rivets, .part-coat, .part-shine, .part-check, .part-crate {
  position: absolute;
  opacity: 0;
  transition: opacity .3s ease;
}
.part-rivets {
  inset: 4px;
  pointer-events: none;
  background:
    radial-gradient(circle 2px at 4px 4px, #1a2133 60%, transparent 62%),
    radial-gradient(circle 2px at calc(100% - 4px) 4px, #1a2133 60%, transparent 62%),
    radial-gradient(circle 2px at 4px calc(100% - 4px), #1a2133 60%, transparent 62%),
    radial-gradient(circle 2px at calc(100% - 4px) calc(100% - 4px), #1a2133 60%, transparent 62%);
}
.part-coat {
  inset: 0;
  border-radius: inherit;
  background: linear-gradient(150deg, #4f8bff 0%, #2f5fcf 50%, #1d3f99 100%);
  box-shadow: inset 0 -4px 8px rgba(0,0,0,0.35);
}
.part-shine {
  inset: 0;
  border-radius: inherit;
  background: linear-gradient(180deg, rgba(255,255,255,0.35) 0%, transparent 45%);
  mix-blend-mode: screen;
}
.part-check {
  top: -10px; right: -10px;
  width: 22px; height: 22px;
  display: grid; place-items: center;
  font-size: 13px; font-weight: 800;
  color: #04210f;
  background: var(--green);
  border-radius: 50%;
  box-shadow: 0 0 0 3px rgba(34,197,94,0.2);
  transform: scale(0);
  transition: opacity .3s ease, transform .3s cubic-bezier(.2,1.4,.4,1);
}
.part-crate {
  inset: -10px -8px;
  border-radius: 4px;
  background:
    repeating-linear-gradient(45deg, rgba(168,85,247,0.18) 0 6px, transparent 6px 12px),
    #6b4a2a;
  border: 2px solid #4a3318;
  box-shadow: 0 8px 16px rgba(0,0,0,0.5);
}
.crate-tape {
  position: absolute;
  top: 50%; left: -8px; right: -8px;
  height: 8px;
  transform: translateY(-50%);
  background: rgba(245, 158, 11, 0.75);
}

/* STAGE EVOLUTION (cumulative) */
/* stage 1: stamped — rounded, lighter, beveled */
.part[data-stage="1"] .part-body,
.part[data-stage="2"] .part-body,
.part[data-stage="3"] .part-body,
.part[data-stage="4"] .part-body,
.part[data-stage="5"] .part-body {
  border-radius: 9px;
  background: #525c70;
  box-shadow: inset 0 -4px 0 rgba(0,0,0,0.3), inset 0 2px 0 rgba(255,255,255,0.12);
}
/* stage 2: rivets */
.part[data-stage="2"] .part-rivets,
.part[data-stage="3"] .part-rivets,
.part[data-stage="4"] .part-rivets,
.part[data-stage="5"] .part-rivets { opacity: 1; }
/* stage 3: paint + shine */
.part[data-stage="3"] .part-coat,
.part[data-stage="4"] .part-coat,
.part[data-stage="5"] .part-coat { opacity: 1; }
.part[data-stage="3"] .part-shine,
.part[data-stage="4"] .part-shine,
.part[data-stage="5"] .part-shine { opacity: 1; }
/* stage 4: inspection check */
.part[data-stage="4"] .part-check,
.part[data-stage="5"] .part-check { opacity: 1; transform: scale(1); }
/* stage 5: crated */
.part[data-stage="5"] .part-crate { opacity: 1; }

/* ---------- CAPTION ---------- */
.caption {
  position: relative;
  z-index: 3;
  text-align: center;
  padding: 0 16px;
  max-width: 620px;
  margin: 0 auto;
}
.caption-tag {
  display: inline-block;
  font-family: var(--mono);
  font-size: 11px;
  letter-spacing: 0.18em;
  color: var(--amber);
  margin-bottom: 6px;
}
.caption-name {
  font-size: clamp(22px, 3.4vw, 34px);
  margin: 0 0 6px;
  font-weight: 800;
  letter-spacing: -0.01em;
}
.caption-desc {
  margin: 0 auto;
  max-width: 520px;
  color: var(--muted);
  font-size: clamp(13px, 1.3vw, 15px);
}

/* ---------- HINT ---------- */
.stage-hint {
  position: relative;
  z-index: 3;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 6px;
  padding-bottom: 14px;
  color: var(--muted-2);
  font-size: 11px;
  letter-spacing: 0.16em;
  font-family: var(--mono);
}
.hint-arrow {
  width: 1px; height: 22px;
  background: linear-gradient(180deg, var(--muted-2), transparent);
  animation: hintBob 1.8s ease-in-out infinite;
}
@keyframes hintBob {
  0%, 100% { transform: translateY(0); opacity: 0.4; }
  50% { transform: translateY(6px); opacity: 1; }
}

/* ---------- MODE TOGGLE ---------- */
.mode-toggle {
  position: fixed;
  right: clamp(12px, 3vw, 28px);
  bottom: clamp(12px, 3vh, 28px);
  z-index: 40;
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 10px 14px;
  font-family: var(--mono);
  font-size: 12px;
  font-weight: 600;
  color: var(--text);
  background: rgba(19, 26, 43, 0.92);
  border: 1px solid var(--line-2);
  border-radius: 999px;
  cursor: pointer;
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  box-shadow: 0 10px 28px rgba(0,0,0,0.5);
  transition: border-color .2s, transform .15s;
}
.mode-toggle:hover { border-color: var(--amber); }
.mode-toggle:active { transform: scale(0.97); }
.mode-toggle-dot {
  width: 9px; height: 9px;
  border-radius: 50%;
  background: var(--muted-2);
  transition: background .2s, box-shadow .2s;
}
.mode-toggle-dot[data-active="true"] {
  background: var(--amber);
  box-shadow: 0 0 8px var(--amber);
}
.mode-toggle-sub { color: var(--muted-2); font-weight: 400; }

/* ---------- STATIC (REDUCED MOTION) VIEW ---------- */
.static-exp {
  max-width: 1100px;
  margin: 0 auto;
  padding: clamp(24px, 5vw, 56px) clamp(20px, 5vw, 40px) clamp(40px, 7vw, 80px);
}
.static-head {
  display: flex;
  justify-content: space-between;
  align-items: flex-end;
  gap: 24px;
  flex-wrap: wrap;
  margin-bottom: 28px;
}
.static-head h2 {
  font-size: clamp(24px, 3.4vw, 36px);
  margin: 12px 0 8px;
  font-weight: 800;
  letter-spacing: -0.01em;
}
.static-head p { margin: 0; color: var(--muted); max-width: 560px; }

.static-stage {
  border: 1px solid var(--line);
  border-radius: var(--radius);
  background:
    linear-gradient(180deg, rgba(255,255,255,0.02), transparent),
    var(--panel);
  padding: clamp(18px, 3vw, 32px);
}

.static-roadmap {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  margin-bottom: clamp(20px, 3vw, 32px);
}
.roadmap-pill {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 8px 12px;
  font-size: 13px;
  font-weight: 600;
  color: var(--muted);
  background: var(--panel-2);
  border: 1px solid var(--line);
  border-radius: 999px;
  cursor: pointer;
  transition: color .15s, border-color .15s, background .15s, transform .1s;
}
.roadmap-pill:hover { color: var(--text); border-color: var(--line-2); }
.roadmap-pill:active { transform: translateY(1px); }
.roadmap-pill .roadmap-num { margin-left: 4px; font-family: var(--mono); font-size: 11px; color: var(--muted-2); }
.roadmap-pill.is-reached {
  color: var(--text);
  border-color: color-mix(in srgb, var(--accent) 50%, var(--line));
  background: color-mix(in srgb, var(--accent) 12%, var(--panel-2));
}
.roadmap-pill.is-active {
  color: #1a1206;
  background: var(--accent);
  border-color: var(--accent);
  box-shadow: 0 0 0 3px color-mix(in srgb, var(--accent) 30%, transparent);
}
.roadmap-pill.is-active .roadmap-num { color: rgba(26,18,6,0.65); }

.static-display {
  position: relative;
  display: flex;
  align-items: center;
  gap: 28px;
  padding: 28px 8px;
  border-top: 1px dashed var(--line);
  border-bottom: 1px dashed var(--line);
}
.display-rail {
  position: relative;
  width: clamp(120px, 22vw, 220px);
  flex-shrink: 0;
  display: flex;
  align-items: center;
  justify-content: center;
}
.display-rail-track {
  width: 100%;
  height: 6px;
  border-radius: 999px;
  background: repeating-linear-gradient(90deg, var(--line-2) 0 10px, transparent 10px 18px);
}
.part-lg {
  position: relative;
  left: auto;
  bottom: auto;
  transform: none;
  width: clamp(80px, 12vw, 120px);
  height: clamp(54px, 8vw, 80px);
  flex-shrink: 0;
}
.display-caption {
  flex: 1;
  min-width: 0;
  display: flex;
  flex-direction: column;
  gap: 4px;
}
.display-caption .caption-tag { margin-bottom: 2px; }
.display-caption strong { font-size: clamp(18px, 2.4vw, 26px); font-weight: 800; }
.display-caption em { font-style: normal; color: var(--muted); font-size: 14px; }

.static-controls {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 18px;
  margin-top: clamp(18px, 3vw, 28px);
}
.static-controls button {
  font-family: var(--font);
  font-size: 14px;
  font-weight: 600;
  padding: 10px 18px;
  color: var(--text);
  background: var(--panel-2);
  border: 1px solid var(--line-2);
  border-radius: 10px;
  cursor: pointer;
  transition: border-color .15s, background .15s, transform .1s;
}
.static-controls button:hover:not(:disabled) { border-color: var(--amber); }
.static-controls button:active:not(:disabled) { transform: translateY(1px); }
.static-controls button:disabled { opacity: 0.4; cursor: not-allowed; }
.step-readout {
  font-family: var(--mono);
  font-size: 14px;
  color: var(--muted);
  min-width: 56px;
  text-align: center;
}

.static-cards {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
  gap: 16px;
  margin-top: clamp(32px, 5vw, 56px);
}
.station-card {
  padding: 20px;
  border-radius: var(--radius);
  background: var(--panel);
  border: 1px solid var(--line);
  border-top: 3px solid var(--accent);
  display: flex;
  flex-direction: column;
  gap: 8px;
}
.station-card header { display: flex; align-items: center; gap: 10px; }
.card-icon {
  display: grid; place-items: center;
  width: 34px; height: 34px;
  border-radius: 9px;
  color: var(--accent);
  background: color-mix(in srgb, var(--accent) 14%, var(--panel-2));
}
.card-num {
  font-family: var(--mono);
  font-size: 11px;
  letter-spacing: 0.12em;
  color: var(--muted-2);
}
.station-card h3 {
  margin: 4px 0 2px;
  font-size: 18px;
  display: flex;
  align-items: baseline;
  gap: 8px;
  flex-wrap: wrap;
}
.card-tag {
  font-size: 11px;
  font-weight: 600;
  color: var(--accent);
  letter-spacing: 0.08em;
  text-transform: uppercase;
}
.station-card p { margin: 0; color: var(--muted); font-size: 14px; }
.card-foot { margin-top: auto; padding-top: 10px; }
.card-xform {
  font-family: var(--mono);
  font-size: 11px;
  color: var(--muted-2);
  padding: 3px 8px;
  border: 1px solid var(--line);
  border-radius: 999px;
}

/* ---------- DETAILS ---------- */
.details {
  max-width: 1100px;
  margin: 0 auto;
  padding: clamp(40px, 7vw, 80px) clamp(20px, 5vw, 40px);
  border-top: 1px solid var(--line);
}
.details h2 {
  font-size: clamp(22px, 3vw, 32px);
  margin: 0 0 28px;
  font-weight: 800;
}
.detail-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
  gap: 24px;
}
.detail-grid h3 { font-size: 16px; margin: 0 0 8px; color: var(--text); }
.detail-grid p { margin: 0; color: var(--muted); font-size: 14px; }

/* ---------- FOOTER ---------- */
.site-foot {
  display: flex;
  justify-content: space-between;
  flex-wrap: wrap;
  gap: 8px;
  padding: 24px clamp(20px, 5vw, 40px);
  border-top: 1px solid var(--line);
  color: var(--muted-2);
  font-size: 12px;
  font-family: var(--mono);
}
.site-foot span { display: inline-flex; align-items: center; gap: 6px; }

/* ---------- RESPONSIVE ---------- */
@media (max-width: 640px) {
  .head-meta span { display: none; }
  .station { width: 64px; }
  .station-name { font-size: 11px; }
  .tool-arm { width: 38px; height: 38px; }
  .tool-arm::after { height: 44px; }
  .static-display { flex-direction: column; align-items: flex-start; gap: 16px; }
  .display-rail { width: 100%; }
  .display-rail-track { background: repeating-linear-gradient(90deg, var(--line-2) 0 8px, transparent 8px 14px); }
  .hero-stats { gap: 18px; }
  .mode-toggle-sub { display: none; }
}

@media (max-width: 380px) {
  .station-num { display: none; }
  .tool-arm { width: 34px; height: 34px; }
}

/* respect users who reduce motion at OS level even inside scroll view:
   pause ambient CSS animations only (scroll-driven transforms are JS, unaffected) */
